import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { FaSearch, FaUserCircle } from 'react-icons/fa';

const Navbar = () => {
  const { user, logout } = useAuth();
  const [search, setSearch] = useState("");
  const navigate = useNavigate();

  const handleSearch = (e) => {
    e.preventDefault();
    navigate(`/?q=${search}`);
  };

  return (
    <nav className="bg-gray-900 text-white p-4 flex justify-between items-center sticky top-0 z-40 shadow-lg">
      <Link to="/" className="text-xl font-bold text-orange-500 flex items-center gap-2">
        ☁️ Mini SoundCloud
      </Link>

      <form onSubmit={handleSearch} className="flex-1 max-w-md mx-4 relative">
        <input 
            type="text" 
            placeholder="Search for artists, bands, tracks..." 
            className="w-full py-1 px-3 rounded bg-gray-800 border border-gray-700 focus:outline-none focus:border-gray-500 text-sm"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
        />
        <button type="submit" className="absolute right-2 top-1.5 text-gray-400"><FaSearch /></button>
      </form>

      <div className="flex items-center gap-4 text-sm font-medium">
        <Link to="/" className="hover:text-white text-gray-300">Home</Link>
        {user ? (
            <>
                <Link to="/upload" className="hover:text-white text-gray-300">Upload</Link>
                <div className="flex items-center gap-2 cursor-pointer group relative">
                    <FaUserCircle className="text-xl" />
                    <span>{user.username}</span>
                    <div className="absolute right-0 top-full mt-2 w-32 bg-white text-black rounded shadow-xl hidden group-hover:block">
                        <button onClick={logout} className="block w-full text-left px-4 py-2 hover:bg-gray-100">Logout</button>
                    </div>
                </div>
            </>
        ) : (
            <>
                <Link to="/login" className="border border-white px-3 py-1 rounded hover:bg-white hover:text-gray-900 transition">Sign in</Link>
                <Link to="/register" className="bg-orange-500 px-3 py-1 rounded hover:bg-orange-600 transition">Create account</Link>
            </>
        )}
      </div>
    </nav>
  );
};

export default Navbar;
